window.addEventListener('DOMContentLoaded', () => {
    fix100vh();
    window.addEventListener('resize', () => {
        fix100vh();
        getScrollBarSize()
    })

    getScrollBarSize()

    let dateInputs = document.querySelectorAll('.date-input input')
    dateInputs.forEach(el => {
        let numberOfMonths = 2

        if(window.innerWidth<=576){
            numberOfMonths = 1
        }

        new Lightpick({
            field: el,
            singleDate: false,
            footer: true,
            numberOfMonths: numberOfMonths,
            lang: 'ru',
            locale: {
                tooltip: {
                    one: 'день',
                    few: 'дня',
                    many: 'дней',
                },
                buttons: {
                    reset: 'Сбросить',
                    apply: 'Применить'
                },
                pluralize: function(i, locale) {
                    if ('one' in locale && i % 10 === 1 && !(i % 100 === 11)) return locale.one;
                    if ('few' in locale && i % 10 === Math.floor(i % 10) && i % 10 >= 2 && i % 10 <= 4 && !(i % 100 >= 12 && i % 100 <= 14)) return locale.few;
                    if ('many' in locale && (i % 10 === 0 || i % 10 === Math.floor(i % 10) && i % 10 >= 5 && i % 10 <= 9 || i % 100 === Math.floor(i % 100) && i % 100 >= 11 && i % 100 <= 14)) return locale.many;
                    if ('other' in locale) return locale.other;

                    return '';
                }
            },
            onSelect: function(date){

            }
        });

    })
})

function fix100vh() {
    let vh = window.innerHeight * 0.01;
    document.documentElement.style.setProperty('--vh', `${vh}px`);
}

let actions = document.querySelectorAll(".action")
actions.forEach(action => {
    let openBtn = action.querySelector("._open-action")
    let closeBtn = action.querySelector("._close-action")
    openBtn.onclick = () => {
        action.classList.add("_open")
        body.classList.add("fixed-body")
    }
    closeBtn.onclick = () => {
        action.classList.remove("_open")
        body.classList.remove("fixed-body")
    }
})

let mobFilters = document.querySelectorAll(".mob-filter")
mobFilters.forEach(filter => {
    let openBtn = filter.querySelector("._open-filter")
    let closeBtn = filter.querySelector("._close-filter")
    openBtn.onclick = () => {
        filter.classList.add("_open")
        body.classList.add("fixed-body")
    }
    closeBtn.onclick = () => {
        filter.classList.remove("_open")
        body.classList.remove("fixed-body")
    }
})
