let singleSelects = document.querySelectorAll(".js-single-select")
let multiSelects = document.querySelectorAll(".js-multi-select")
let ranges = document.querySelectorAll(".js-dropdown-range")

ranges.forEach(select => {
    let show = select.querySelector(".m-select__show")
    let num = select.querySelector("._num")
    let from = select.querySelector("._from")
    let to = select.querySelector("._to")

    selectAction()

    function selectAction() {
        let fromValue = from.value.trim()
        let toValue = to.value.trim()

        if(!fromValue && !toValue){
            select.classList.remove("_is-selected-option")
            return
        }

        select.classList.add("_is-selected-option")

        if(!fromValue && toValue){
            num.innerHTML = `от ∞ до ${toValue}`
            return;
        }

        if(fromValue && !toValue){
            num.innerHTML = `от ${fromValue} до ∞`
            return;
        }

        num.innerHTML = `от ${fromValue} до ${toValue}`
    }

    from.onchange = function () {
        selectAction()
    }

    to.onchange = function () {
        selectAction()
    }

    show.onclick = function () {
        select.classList.toggle("_open")
    }

    document.addEventListener( 'click', (e) => {
        const withinBoundaries = e.composedPath().includes(select);

        if ( ! withinBoundaries ) {
            if(select.classList.contains("_open")){
                select.classList.remove("_open")
            }
        }
    })
})


multiSelects.forEach(select => {
    let options = select.querySelectorAll(".m-select__check input")
    let show = select.querySelector(".m-select__show")
    let num = select.querySelector("._num")

    selectAction()

    function selectAction() {
        let selectedOptionsCount = select.querySelectorAll(".m-select__check input:checked").length
        num.innerHTML = selectedOptionsCount
        if(selectedOptionsCount === 0){
            select.classList.remove("_is-selected-option")
        }else{
            select.classList.add("_is-selected-option")
        }
    }

    options.forEach(option => {
        option.onchange = () => {
            selectAction()
        }
    })

    show.onclick = function () {
        select.classList.toggle("_open")
    }

    document.addEventListener( 'click', (e) => {
        const withinBoundaries = e.composedPath().includes(select);

        if ( ! withinBoundaries ) {
            if(select.classList.contains("_open")){
                select.classList.remove("_open")
            }
        }
    })
})


singleSelects.forEach(select => {
    let options = select.querySelectorAll(".m-select__item input")
    let current = select.querySelector(".m-select__current")
    let show = select.querySelector(".m-select__show")

    selectAction()

    function selectAction() {
        let selectedOption = select.querySelector(".m-select__item input:checked")
        if(!selectedOption){
            return
        }
        let val = selectedOption.getAttribute("data-value")
        current.innerHTML = val
        select.classList.add("_is-selected")
    }

    options.forEach(option => {
        option.onchange = () => {
            selectAction()
            select.classList.remove("_open")
        }
    })

    show.onclick = function () {
        select.classList.toggle("_open")
    }

    document.addEventListener( 'click', (e) => {
        const withinBoundaries = e.composedPath().includes(select);

        if ( ! withinBoundaries ) {
            if(select.classList.contains("_open")){
                select.classList.remove("_open")
            }
        }
    })
})
